// Canonicalize the value to its minimal form. This will normalize whitespace,
// and print the important modifier `!` in the correct place.
//
// E.g.:
//
// ```
// [display:_flex_] => [display:flex]
// [display:_flex]  => [display:flex]
// [display:flex_]  => [display:flex]
// [display:flex]   => [display:flex]
// ```
//
export function migrateCanonicalizeCandidate(
  designSystem: DesignSystem,
  _userConfig: Config | null,
  rawCandidate: string,
) {
  for (let readonlyCandidate of designSystem.parseCandidate(rawCandidate)) {
    let canonicalizedCandidate = designSystem.printCandidate(readonlyCandidate)
    if (canonicalizedCandidate !== rawCandidate) {
      return canonicalizedCandidate
    }
  }

  return rawCandidate
}

import { cloneCandidate, parseCandidate } from '../../../../tailwindcss/src/candidate'
import type { Config } from '../../../../tailwindcss/src/compat/plugin-api'
import type { DesignSystem } from '../../../../tailwindcss/src/design-system'
import { segment } from '../../../../tailwindcss/src/utils/segment'

export function migrateLegacyArbitraryValues(
  designSystem: DesignSystem,
  _userConfig: Config | null,
  rawCandidate: string,
): string {
  for (let candidate of parseCandidate(rawCandidate, designSystem)) {
    let clone = cloneCandidate(candidate)
    let changed = false

    // Convert commas to spaces. E.g.: [auto,1fr] to [auto_1fr]
    if (
      clone.kind === 'functional' &&
      clone.value?.kind === 'arbitrary' &&
      (clone.root === 'grid-cols' || clone.root == 'grid-rows' || clone.root == 'object')
    ) {
      changed = true
      clone.value.value = segment(clone.value.value, ',').join(' ')
    }

    return changed ? designSystem.printCandidate(clone) : rawCandidate
  }

  return rawCandidate
}

import { ensureTailwind } from "./ensure-tailwind";
import { installPackage } from "./install";
import { setupClassList } from "./setup-class-list";
import { setupConfig } from "./setup-config";
import { setupGitIgnore } from "./setup-gitignore";
import { setupInit } from "./setup-init";
import { setupOutputDirectory } from "./setup-output-directory";
import { setupPlugin } from "./setup-plugin";
import { setupRegister } from "./setup-register";
import { setupTailwind } from "./setup-tailwind";
import { setupVSCode } from "./setup-vscode";

export async function init() {
  try {
    await ensureTailwind();
    await installPackage();
    await setupOutputDirectory();
    await setupGitIgnore();
    await setupClassList();
    const config = await setupConfig();
    await setupInit(config);
    await setupVSCode();
    await setupTailwind();
    const hasBundler = await setupPlugin();
    if (!hasBundler) {
      await setupRegister();
    }
    console.log("\n✅ Flowbite React has been successfully initialized!");
  } catch (error) {
    console.error("An error occurred during initialization:", error);
    process.exit(1);
  }
}

// Given a version, figure out what the release notes are so that we can use this to pre-fill the
// release notes on a GitHub release for the current version.

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import * as url from 'node:url'

const __dirname = path.dirname(url.fileURLToPath(import.meta.url))

let version = process.argv[2] || process.env.npm_package_version
if (!version) {
  let pkgPath = path.resolve(__dirname, '../packages/tailwindcss/package.json')
  let pkg = await fs.readFile(pkgPath, 'utf8').then(JSON.parse)

  version = pkg.version
}

let changelog = await fs.readFile(path.resolve(__dirname, '..', 'CHANGELOG.md'), 'utf8')
let match = new RegExp(
  `## \\[${version}\\] - (.*)\\n\\n([\\s\\S]*?)\\n(?:(?:##\\s)|(?:\\[))`,
  'g',
).exec(changelog)

if (match) {
  let [, , notes] = match
  console.log(notes.trim())
} else {
  console.log(`Placeholder release notes for version: v${version}`)
}
